<script setup lang="ts">
import { ref, computed } from 'vue'
import GameLayout from '@/layouts/GameLayout.vue'
import PageFrame from '@/components/common/PageFrame.vue'
import WeaponIcon from '@/components/common/WeaponIcon.vue'
import { useWeaponStore } from '@/stores/weapon'
import {
  weapons,
  TIER_META,
  statsAtTier,
  nextTier,
  UPGRADE_COST,
  type WeaponTier,
} from '@/data/weapons'

type Filter = 'all' | 'awaken1' | 'awaken2' | 'has-artifact'

const weaponStore = useWeaponStore()

const activeFilter = ref<Filter>('all')
const selectedTier = ref<WeaponTier>('base')
const selectedWeaponId = ref<number | null>(null)
const toast = ref<string>('')
let toastTimer: ReturnType<typeof setTimeout> | null = null

const filteredWeapons = computed(() => {
  if (activeFilter.value === 'awaken1') return weapons.filter((w) => w.awakenType === 1)
  if (activeFilter.value === 'awaken2') return weapons.filter((w) => w.awakenType === 2)
  if (activeFilter.value === 'has-artifact') return weapons.filter((w) => !!w.artifact)
  return weapons
})

const selectedWeapon = computed(() =>
  selectedWeaponId.value ? weapons.find((w) => w.id === selectedWeaponId.value) : null,
)

// 当前查看武器的实际形态(取自 store,以便升级后实时同步)
const selectedCurrentTier = computed<WeaponTier>(() => {
  if (!selectedWeapon.value) return 'base'
  return weaponStore.currentTierOf(selectedWeapon.value.id)
})

const selectedStats = computed(() => {
  if (!selectedWeapon.value) return null
  return statsAtTier(selectedWeapon.value, selectedCurrentTier.value)
})

const selectedNextTier = computed<WeaponTier | null>(() => {
  return nextTier(selectedCurrentTier.value)
})

const selectedNextStats = computed(() => {
  if (!selectedWeapon.value || !selectedNextTier.value) return null
  return statsAtTier(selectedWeapon.value, selectedNextTier.value)
})

const selectedUpgradeCost = computed(() => UPGRADE_COST[selectedCurrentTier.value])

function selectWeapon(id: number) {
  selectedWeaponId.value = selectedWeaponId.value === id ? null : id
}
function closeDetail() {
  selectedWeaponId.value = null
}
function doUpgrade() {
  if (!selectedWeapon.value) return
  const r = weaponStore.upgrade(selectedWeapon.value.id)
  if (r.ok) {
    showToast(
      `✨ 升级成功!${selectedWeapon.value.base} → ${selectedWeapon.value[selectedCurrentTier.value] ?? '?'}`,
    )
  } else {
    showToast(`❌ ${r.reason}`)
  }
}
function showToast(msg: string) {
  toast.value = msg
  if (toastTimer) clearTimeout(toastTimer)
  toastTimer = setTimeout(() => (toast.value = ''), 2000)
}
</script>

<template>
  <GameLayout>
    <PageFrame title="背包" subtitle="Inventory · 我的 25 把武器" emoji="🎒">
      <!-- 分类筛选 -->
      <div class="flex gap-1.5 mb-3 flex-wrap">
        <button
          v-for="f in [
            { key: 'all', label: `全部 ${weapons.length}` },
            { key: 'awaken1', label: '觉醒1' },
            { key: 'awaken2', label: '觉醒2' },
            { key: 'has-artifact', label: '已神器化' },
          ]"
          :key="f.key"
          class="px-3 py-1 rounded text-[12px] font-bold"
          :class="
            activeFilter === f.key
              ? 'bg-amber-600 text-white'
              : 'bg-black/40 text-amber-200 hover:bg-black/60'
          "
          @click="activeFilter = f.key as Filter"
        >
          {{ f.label }}
        </button>

        <div class="flex-1" />

        <!-- 形态预览选择 -->
        <div class="flex items-center gap-1 text-[12px] text-amber-200/80">
          形态:
          <button
            v-for="t in ['base', 'upgrade', 'ten', 'artifact'] as WeaponTier[]"
            :key="t"
            class="px-2 py-0.5 rounded text-[11px] font-bold"
            :class="
              selectedTier === t
                ? `${TIER_META[t].bg} ${TIER_META[t].text} ring-1 ${TIER_META[t].border}`
                : 'bg-black/30 text-slate-400 hover:text-amber-200'
            "
            @click="selectedTier = t"
          >
            {{ TIER_META[t].label }}
          </button>
        </div>
      </div>

      <!-- 武器网格 -->
      <div class="grid grid-cols-5 gap-3">
        <button
          v-for="w in filteredWeapons"
          :key="w.id"
          class="flex flex-col items-center gap-1 p-2 rounded-lg bg-black/40 border border-amber-700/30 hover:border-amber-400 hover:bg-black/60 transition"
          :class="{ 'ring-2 ring-amber-400': selectedWeaponId === w.id }"
          @click="selectWeapon(w.id)"
        >
          <WeaponIcon
            :weapon="w"
            :tier="weaponStore.currentTierOf(w.id) as WeaponTier"
            :size="56"
          />
          <div class="text-[12px] text-amber-100 truncate max-w-full">
            {{ w[weaponStore.currentTierOf(w.id) as WeaponTier] ?? w.base }}
          </div>
        </button>
      </div>
    </PageFrame>

    <!-- 武器详情弹层 -->
    <Teleport to="body">
      <div
        v-if="selectedWeapon"
        class="fixed inset-0 z-50 flex items-center justify-center bg-black/60"
        @click.self="closeDetail"
      >
        <div
          class="w-[520px] max-w-[90vw] rounded-xl bg-slate-900 border-2 border-amber-500 shadow-2xl overflow-hidden"
        >
          <header
            class="flex items-center gap-3 px-4 py-3 bg-gradient-to-r from-amber-900/80 to-rose-900/80 border-b border-amber-600/60"
          >
            <WeaponIcon :weapon="selectedWeapon" :tier="selectedCurrentTier" :size="64" />
            <div class="flex-1">
              <h3 class="text-amber-200 text-lg font-bold">
                {{ selectedWeapon.base }}
              </h3>
              <p class="text-amber-100/70 text-[12px]">
                觉醒 {{ selectedWeapon.awakenType }} · 当前形态:
                {{ TIER_META[selectedCurrentTier].label }}
              </p>
            </div>
            <button
              class="w-8 h-8 rounded-full bg-black/40 text-amber-200 hover:bg-black/60"
              @click="closeDetail"
            >
              ✕
            </button>
          </header>

          <!-- 4 项属性 -->
          <div v-if="selectedStats" class="p-4">
            <div class="text-amber-200 text-[14px] font-bold mb-2">📊 属性</div>
            <div class="grid grid-cols-2 gap-2 text-[12px]">
              <div
                v-for="(val, key) in {
                  '⚔️ 攻击': selectedStats.atk,
                  '🛡️ 防御': selectedStats.def,
                  '⚡ 速度': selectedStats.spd,
                  '💥 暴击': `${selectedStats.crit}%`,
                }"
                :key="key"
                class="flex justify-between px-2 py-1 rounded bg-black/40 border border-amber-700/30"
              >
                <span class="text-slate-300">{{ key }}</span>
                <span class="text-amber-200 font-bold">{{ val }}</span>
              </div>
            </div>
          </div>

          <!-- 4 段形态列表 -->
          <div class="px-4 pb-3 space-y-1.5">
            <div
              v-for="t in ['base', 'upgrade', 'ten', 'artifact'] as WeaponTier[]"
              v-show="selectedWeapon[t]"
              :key="t"
              class="flex items-center gap-3 px-3 py-2 rounded-lg"
              :class="[TIER_META[t].bg, t === selectedCurrentTier ? `ring-2 ring-amber-400` : '']"
            >
              <span
                class="px-2 py-0.5 rounded text-[11px] font-bold border"
                :class="`${TIER_META[t].text} ${TIER_META[t].border}`"
              >
                {{ TIER_META[t].label }}
              </span>
              <span class="flex-1 text-amber-100 text-[14px]">
                {{ selectedWeapon[t] }}
              </span>
              <WeaponIcon :weapon="selectedWeapon" :tier="t" :size="32" />
            </div>

            <div
              v-if="selectedWeapon.intermediate?.length"
              class="mt-2 p-2 rounded bg-black/30 border border-amber-700/30"
            >
              <div class="text-amber-200 text-[12px] font-bold mb-1">🔀 过渡形态</div>
              <div class="flex flex-wrap gap-1">
                <span
                  v-for="n in selectedWeapon.intermediate"
                  :key="n"
                  class="px-2 py-0.5 rounded text-[11px] bg-emerald-900/40 text-emerald-200 border border-emerald-700/40"
                >
                  {{ n }}
                </span>
              </div>
            </div>
          </div>

          <!-- 升级按钮区 -->
          <div class="px-4 pb-4">
            <div
              v-if="selectedNextTier && selectedUpgradeCost != null"
              class="p-3 rounded-lg bg-emerald-900/30 border border-emerald-700/40"
            >
              <div class="flex items-center gap-2 text-[12px] text-emerald-200 mb-2">
                <span>下一形态:</span>
                <span class="font-bold">
                  {{ TIER_META[selectedNextTier].label }} ·
                  {{ selectedWeapon[selectedNextTier] }}
                </span>
              </div>
              <div
                v-if="selectedNextStats"
                class="grid grid-cols-2 gap-1 text-[11px] text-emerald-100/80 mb-2"
              >
                <div>+{{ selectedNextStats.atk - (selectedStats?.atk ?? 0) }} 攻击</div>
                <div>+{{ selectedNextStats.def - (selectedStats?.def ?? 0) }} 防御</div>
                <div>+{{ selectedNextStats.spd - (selectedStats?.spd ?? 0) }} 速度</div>
                <div>+{{ selectedNextStats.crit - (selectedStats?.crit ?? 0) }}% 暴击</div>
              </div>
              <div class="flex items-center gap-2">
                <button
                  class="flex-1 px-3 py-1.5 rounded bg-gradient-to-r from-amber-500 to-orange-500 text-white font-bold text-[13px] hover:brightness-110 active:scale-95"
                  @click="doUpgrade"
                >
                  升级 ({{ selectedUpgradeCost.toLocaleString() }} 🪙)
                </button>
                <div class="text-[11px] text-amber-200/80">
                  余额 {{ weaponStore.gold.toLocaleString() }} 🪙
                </div>
              </div>
            </div>
            <div
              v-else
              class="p-3 rounded-lg bg-amber-900/30 border border-amber-700/40 text-center text-amber-200 text-[12px] font-bold"
            >
              👑 已达最高形态(神器)
            </div>
          </div>
        </div>
      </div>
    </Teleport>

    <!-- Toast 提示 -->
    <Teleport to="body">
      <div
        v-if="toast"
        class="fixed top-20 left-1/2 -translate-x-1/2 z-[60] px-4 py-2 rounded-lg bg-amber-500 text-white font-bold text-[14px] shadow-2xl"
      >
        {{ toast }}
      </div>
    </Teleport>
  </GameLayout>
</template>
