import { defineStore } from 'pinia';
import { weaponById } from '@/data/weapons';
/**
 * 武器状态 store
 * 阶段 0 纯前端,刷新不持久化;后续接后端时改 fetch
 */
export const useWeaponStore = defineStore('weapon', {
    state: () => ({
        currentTiers: {},
        gold: 100000,
    }),
    getters: {
        /** 取某武器当前形态(无则回退 base) */
        currentTierOf: (s) => (id) => {
            return s.currentTiers[id] ?? 'base';
        },
    },
    actions: {
        /** 把指定武器升到下一形态(无下一形态返回 false) */
        upgrade(id) {
            const w = weaponById(id);
            if (!w)
                return { ok: false, reason: '武器不存在' };
            const cur = this.currentTierOf(id);
            const order = ['base', 'upgrade', 'ten', 'artifact'];
            const idx = order.indexOf(cur);
            if (idx < 0 || idx >= order.length - 1) {
                return { ok: false, reason: '已是最高形态' };
            }
            const next = order[idx + 1];
            if (!w[next]) {
                return { ok: false, reason: '该武器无此进阶路径' };
            }
            const cost = [0, 1000, 5000, 20000][idx];
            if (this.gold < cost) {
                return { ok: false, reason: `金币不足,需要 ${cost}` };
            }
            this.gold -= cost;
            this.currentTiers = { ...this.currentTiers, [id]: next };
            return { ok: true };
        },
        /** 重置单把武器到基础(开发期) */
        resetWeapon(id) {
            const cp = { ...this.currentTiers };
            delete cp[id];
            this.currentTiers = cp;
        },
    },
});
